SELECT * FROM (
  SELECT ROWNUM rnum, A.* FROM (
    SELECT 
      memberno, id, mname, tel, address1, mdate, grade
    FROM member 


        id LIKE '%' || #{keyword} || '%' 
        OR mname LIKE '%' || #{keyword} || '%'


    ORDER BY memberno DESC
  ) A WHERE ROWNUM <= #{end}  
) WHERE rnum >= #{start}

